    27	void
    28	print_token(const antlr4::Token* token,
    29	            const antlr4::CommonTokenStream& tokens,
    30	            std::ofstream& outFile,
    31	            const antlr4::Lexer& lexer)
    32	{
    33	  auto& vocabulary = lexer.getVocabulary();
    34	
    35	  auto tokenTypeName =
    36	    std::string(vocabulary.getSymbolicName(token->getType()));
    37	
    38	  if (tokenTypeName.empty())
    39	    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况
    40	
    41	  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    42	    tokenTypeName = tokenTypeMapping[tokenTypeName];
    43	  }
    44	  std::string locInfo = " Loc=<0:0>";
    45	
    46	  bool startOfLine = false;
    47	  bool leadingSpace = false;
    48	
    49	  if (token->getText() != "<EOF>")
    50	    outFile << tokenTypeName << " '" << token->getText() << "'";
    51	  else
    52	    outFile << tokenTypeName << " '"
    53	            << "'";
    54	  if (startOfLine)
    55	    outFile << "\t [StartOfLine]";
    56	  if (leadingSpace)
    57	    outFile << " [LeadingSpace]";
    58	  outFile << locInfo << std::endl;
    59	}
    60	
    61	int
    62	main(int argc, char* argv[])
    63	{
    64	  if (argc != 3) {
    65	    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    66	    return -1;
    67	  }
    68	
    69	  std::ifstream inFile(argv[1]);
    70	  if (!inFile) {
    71	    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    72	    return -2;
    73	  }
    74	
    75	  std::ofstream outFile(argv[2]);
    76	  if (!outFile) {
    77	    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    78	    return -3;
    79	  }
    80	
    81	  std::cout << "程序 '" << argv[0] << std::endl;
    82	  std::cout << "输入 '" << argv[1] << std::endl;
    83	  std::cout << "输出 '" << argv[2] << std::endl;
    84	
    85	  antlr4::ANTLRInputStream input(inFile);
    86	  SYsULexer lexer(&input);
    87	
    88	  antlr4::CommonTokenStream tokens(&lexer);
    89	  tokens.fill();
    90	
    91	  for (auto&& token : tokens.getTokens()) {
    92	    print_token(token, tokens, outFile, lexer);
    93	  }
    94	}
