Default : 'default';

LeftParen : '(';
RightParen : ')';
LeftBracket : '[';
RightBracket : ']';
LeftBrace : '{';
RightBrace : '}';

Plus : '+';
Minus : '-';
Multiply : '*';
Divide : '/';
Modulo : '%';
Assign : '=';
PlusAssign : '+=';
MinusAssign : '-=';
MulAssign : '*=';
DivAssign : '/=';
ModAssign : '%=';

Semi : ';';
Comma : ',';
Dot : '.';
Colon : ':';

Equal : '==';
NotEqual : '!=';
Less : '<';
LessEqual : '<=';
Greater : '>';
GreaterEqual : '>=';

LogicalAnd : '&&';
LogicalOr : '||';
LogicalNot : '!';

BitwiseAnd : '&';
BitwiseOr : '|';
BitwiseXor : '^';
BitwiseNot : '~';
LeftShift : '<<';
RightShift : '>>';

Increment : '++';
Decrement : '--';

Identifier
    :   IdentifierNondigit
        (   IdentifierNondigit
        |   Digit
        )*
    ;

fragment
IdentifierNondigit
    :   Nondigit
    ;

fragment
Nondigit
    :   [a-zA-Z_]
    ;

fragment
Digit
    :   [0-9]
    ;

Constant
    :   IntegerConstant
    ;

fragment
IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;


fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;

StringLiteral
    :   '"' (EscapeSequence | ~('\\'|'"'))* '"'
    ;

fragment
EscapeSequence
    :   '\\' ['"?\\abfnrtv]
    ;

CharacterLiteral
    :   '\'' (EscapeSequence | ~('\'')) '\''
    ;

// 预处理信息处理，可以从预处理信息中获得文件名以及行号
// 预处理信息中的第一个数字即为行号
LineAfterPreprocessing
    :   '#' Whitespace* ~[\r\n]*
        -> skip
    ;

Whitespace
    :   [ \t]+
        -> skip
    ;

// 换行符号，可以利用这个信息来更新行号
Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        -> skip
    ;

