   220	/// Rewrite as many loads as possible given a single store.
   221	///
   222	/// When there is only a single store, we can use the domtree to trivially
   223	/// replace all of the dominated loads with the stored value. Do so, and return
   224	/// true if this has successfully promoted the alloca entirely. If this returns
   225	/// false there were some loads which were not dominated by the single store
   226	/// and thus must be phi-ed with undef. We fall back to the standard alloca
   227	/// promotion algorithm in that case.
   228	static bool
   229	rewriteSingleStoreAlloca(AllocaInst* AI,
   230	                         AllocaInfo& Info,
   231	                         LargeBlockInfo& LBI,
   232	                         DominatorTree& DT)
   233	{
   234	  StoreInst* OnlyStore = Info.OnlyStore;
   235	  bool StoringGlobalVal = !isa<Instruction>(OnlyStore->getOperand(0));
   236	  BasicBlock* StoreBB = OnlyStore->getParent();
   237	  int StoreIndex = -1;
   238	
   239	  // Clear out UsingBlocks.  We will reconstruct it here if needed.
   240	  Info.UsingBlocks.clear();
   241	
   242	  for (User* U : make_early_inc_range(AI->users())) {
   243	    Instruction* UserInst = cast<Instruction>(U);
   244	    if (UserInst == OnlyStore)
   245	      continue;
   246	    LoadInst* LI = cast<LoadInst>(UserInst);
   247	
   248	    // Okay, if we have a load from the alloca, we want to replace it with the
   249	    // only<response clipped><NOTE>Due to the max output limit, only part of this file has been shown to you. You should retry this tool after you have searched inside the file with `grep -n` in order to find the line numbers of what you are looking for.</NOTE>   continue;
   250	
   251	    // Okay, this is a block that both uses and defines the value.  If the first
   252	    // reference to the alloca is a def (store), then we know it isn't live-in.
   253	    for (BasicBlock::iterator I = BB->begin();; ++I) {
   254	      if (StoreInst* SI = dyn_cast<StoreInst>(I)) {
   255	        if (SI->getOperand(1) != AI)
   256	          continue;
   257	
   258	        // We found a store to the alloca before a load.  The alloca is not
   259	        // actually live-in here.
   260	        LiveInBlockWorklist[i] = LiveInBlockWorklist.back();
   261	        LiveInBlockWorklist.pop_back();
   262	        --i;
   263	        --e;
   264	        break;
   265	      }
   266	
   267	      if (LoadInst* LI = dyn_cast<LoadInst>(I))
   268	        // Okay, we found a load before a store to the alloca.  It is actually
   269	        // live into this block.
   270	        if (LI->getOperand(0) == AI)
   271	          break;
   272	    }
   273	  }
   274	
   275	  // Now that we have a set of blocks where the phi is live-in, recursively add
   276	  // their predecessors until we find the full region the value is live.
   277	  while (!LiveInBlockWorklist.empty()) {
   278	    BasicBlock* BB = LiveInBlockWorklist.pop_back_val();
   279	
   280	    // The block really is live in here, insert it into the set.  If already in
   281	    // the set, then it has already been processed.
   282	    if (!LiveInBlocks.insert(BB).second)
   283	      continue;
   284	
   285	    // Since the value is live into BB, it is either defined in a predecessor or
   286	    // live into it to.  Add the preds to the worklist unless they are a
   287	    // defining block.
   288	    for (BasicBlock* P : predecessors(BB)) {
   289	      // The value is not live into a predecessor if it defines the value.
   290	      if (DefBlocks.count(P))
   291	        continue;
   292	
   293	      // Otherwise it is, add to the worklist.
   294	      LiveInBlockWorklist.push_back(P);
   295	    }
   296	  }
   297	}
