    56	class FuncLowering final {
    57	public:
    58	  // 保存模块信息、数据布局和汇编输出器，作为整个函数翻译阶段的上下文。
    59	  FuncLowering(const llvm::Module& m, RvAsmEmitter& as)
    60	      : mod_(m)
    61	      , dl_(m.getDataLayout())
    62	      , as_(as)
    63	  {
    64	  }
    65	
    66	  // 把一个 LLVM 函数整体翻译成 MIR，再交给寄存器分配和汇编输出。
    67	  void emitFunction(const llvm::Function& f)
    68	  {
    69	    if (f.isDeclaration())
    70	      return;
    71	    if (f.getName().starts_with("llvm."))
    72	      return;
    73	
    74	    resetForFunction(f);
    75	    computeFrameLayoutBase(f);
    76	
    77	    as_.emitDirective("\t.text");
    78	    as_.emitDirective("\t.align 2");
    79	    as_.emitDirective(("\t.globl " + f.getName()).str());
    80	    as_.emitDirective(("\t.type " + f.getName() + ", @function").str());
    81	    as_.emitLabel(f.getName());
    82	
    83	    emitPrologue();
    84	    spillIncomingArgs(f);
    85	
    86	    LinearScanAllocator ra;
    87	    RvInstEmitter emitter(as_, vregSpill_, localBytes_, saveRaOff_, saveS0Off_);
    88	
    89	    for (const llvm::BasicBlock& bb : f) {
    90	      as_.emitLabel(bbLabel(bb));
    91	      insts_.clear();
    92	      pendingEdges_.clear();
    93	      curBB_ = &bb;
    94	      for (const llvm::Instruction& inst : bb) {
    95	        if (llvm::isa<llvm::PHINode>(inst))
    96	          continue;
    97	        emitInst(inst);
    98	      }
    99	      ra.allocate(insts_);
   100	      emitter.emit(insts_, ra.physMap());
   101	      for (const EdgeBlock& edge : pendingEdges_) {
   102	        as_.emitLabel(edge.label);
   103	        insts_.clear();
   104	        emitPhiMoves(edge.moves);
   105	        emitVBranchUncond(edge.target);
   106	        ra.allocate(insts_);
   107	        emitter.emit(insts_, ra.physMap());
   108	      }
   109	    }
   110	  }
