   112	private:
   113	  const llvm::Module& mod_;
   114	  const llvm::DataLayout& dl_;
   115	  RvAsmEmitter& as_;
   116	
   117	  const llvm::Function* curF_ = nullptr;
   118	  const llvm::BasicBlock* curBB_ = nullptr;
   119	  llvm::DenseMap<const llvm::BasicBlock*, std::string> bbLabel_;
   120	  llvm::DenseMap<const llvm::Value*, llvm::Register> valueVReg_;
   121	  llvm::DenseMap<llvm::Register, int32_t> vregSpill_;
   122	  llvm::DenseMap<const llvm::AllocaInst*, int32_t> allocaOff_;
   123	  int32_t localBytes_ = 0;
   124	  int32_t saveRaOff_ = 0;
   125	  int32_t saveS0Off_ = 0;
   126	  unsigned nextVReg_ = 1;
   127	  unsigned tempSlots_ = 8;
   128	  llvm::SmallVector<llvm::Register, 8> tempVRegs_;
   129	  unsigned tempCursor_ = 0;
   130	  llvm::SmallVector<VInst, 64> insts_;
   131	  unsigned edgeId_ = 0;
   132	
   133	  struct PhiMove final {
   134	    llvm::Register dst;
   135	    const llvm::Value* src = nullptr;
   136	  };
   137	
   138	  struct EdgeBlock final {
   139	    std::string label;
   140	    std::string target;
   141	    llvm::SmallVector<PhiMove, 4> moves;
   142	  };
   143	
   144	  llvm::SmallVector<EdgeBlock, 4> pendingEdges_;
