   146	  // 申请一个新的虚拟寄存器，表示“这个值先放在哪里”。
   147	  llvm::Register newVReg()
   148	  {
   149	    return llvm::Register::index2VirtReg(nextVReg_++);
   150	  }
   151	
   152	  // 开始处理新函数前重置状态，并给每个基本块分配一个汇编标签。
   153	  void resetForFunction(const llvm::Function& f)
   154	  {
   155	    curF_ = &f;
   156	    bbLabel_.clear();
   157	    valueVReg_.clear();
   158	    vregSpill_.clear();
   159	    allocaOff_.clear();
   160	    nextVReg_ = 1;
   161	    tempVRegs_.clear();
   162	    tempCursor_ = 0;
   163	    insts_.clear();
   164	
   165	    unsigned bb_id = 0;
   166	    for (const llvm::BasicBlock& bb : f) {
   167	      bbLabel_[&bb] = (".Lbb." + f.getName() + "." + std::to_string(bb_id++)).str();
   168	    }
   169	  }
   170	
   171	  // 查询基本块对应的标签，分支和跳转都会用到它。
   172	  std::string bbLabel(const llvm::BasicBlock& bb) const
   173	  {
   174	    auto it = bbLabel_.find(&bb);
   175	    assert(it != bbLabel_.end());
   176	    return it->second;
   177	  }
