   271	  // 输出函数序言：开栈帧、保存返回地址和帧指针，并建立新的 s0。
   272	  void emitPrologue()
   273	  {
   274	    as_.emitLine("addi sp, sp, -" + std::to_string(localBytes_));
   275	    as_.emitLine("sd ra, " + std::to_string(saveRaOff_) + "(sp)");
   276	    as_.emitLine("sd s0, " + std::to_string(saveS0Off_) + "(sp)");
   277	    as_.emitLine("addi s0, sp, " + std::to_string(localBytes_));
   278	  }
