   280	  // 把形参统一写回栈槽，后续就能像普通 SSA 值一样按虚拟寄存器处理。
   281	  void spillIncomingArgs(const llvm::Function& f)
   282	  {
   283	    unsigned idx = 0;
   284	    for (const llvm::Argument& arg : f.args()) {
   285	      int32_t <response clipped><NOTE>Due to the max output limit, only part of this file has been shown to you. You should retry this tool after you have searched inside the file with `grep -n` in order to find the line numbers of what you are looking for.</NOTE>i.getFalseValue());
   286	    llvm::Register dst = vregOf(&si);
   287	
   288	    llvm::Register tmp = nextTempVReg();
   289	    llvm::Register tmp2 = nextTempVReg();
   290	    emitVSub(tmp, tv, fv);
   291	    emitVMul(tmp2, cond, tmp);
   292	    emitVAdd(dst, fv, tmp2);
