   295	  // 翻译 br，同时处理 PHI 需要的边上复制。
   296	  // 关键点是：真正的 PHI move 不放在前驱块末尾，而是放进单独的 edge block。
   297	  void emitBranchInst(const llvm::BranchInst& bi)
   298	  {
   299	    if (!curBB_)
   300	      llvm::report_fatal_error("missing current basic block");
   301	
   302	    if (bi.isUnconditional()) {
   303	      const llvm::BasicBlock* succ = bi.getSuccessor(0);
   304	      auto moves = collectPhiMoves(*curBB_, *succ);
   305	      std::string target = bbLabel(*succ);
   306	      if (!moves.empty()) {
   307	        std::string edgeLabel = makeEdgeLabel();
   308	        pendingEdges_.push_back(EdgeBlock{edgeLabel, target, std::move(moves)});
   309	        emitVBranchUncond(edgeLabel);
   310	      } else {
   311	        emitVBranchUncond(target);
   312	      }
   313	      return;
   314	    }
   315	
   316	    llvm::Register cond = emitLoadValue(bi.getCondition());
   317	    const llvm::BasicBlock* tbb = bi.getSuccessor(0);
   318	    const llvm::BasicBlock* fbb = bi.getSuccessor(1);
   319	
   320	    auto tMoves = collectPhiMoves(*curBB_, *tbb);
   321	    auto fMoves = collectPhiMoves(*curBB_, *fbb);
   322	
   323	    std::string tLabel = tMoves.empty() ? bbLabel(*tbb) : makeEdgeLabel();
   324	    std::string fLabel = fMoves.empty() ? bbLabel(*fbb) : makeEdgeLabel();
   325	
   326	    if (!tMoves.empty())
   327	      pendingEdges_.push_back(EdgeBlock{tLabel, bbLabel(*tbb), std::move(tMoves)});
   328	    if (!fMoves.empty())
   329	      pendingEdges_.push_back(EdgeBlock{fLabel, bbLabel(*fbb), std::move(fMoves)});
   330	
   331	    emitVBranchCond(cond, tLabel, false);
   332	    emitVBranchUncond(fLabel);
   333	  }
   334	
   335	  // 翻译 switch：逐个 case 比较，相等就跳走，最后落到 default。
   336	  // 它和条件分支一样，也要照顾目标块里的 PHI 赋值。
   337	  void emitSwitchInst(const llvm::SwitchInst& si)
   338	  {
   339	    if (!curBB_)
   340	      llvm::report_fatal_error("missing current basic block");
   341	
   342	    llvm::Register val = emitLoadValue(si.getCondition());
   343	    for (const auto& c : si.cases()) {
   344	      int64_t imm = c.getCaseValue()->getSExtValue();
   345	      llvm::Register caseReg = nextTempVReg();
   346	      emitVLoadImm(caseReg, imm);
   347	      llvm::Register tmp = nextTempVReg();
   348	      emitVXor(tmp, val, caseReg);
   349	      llvm::Register iseq = nextTempVReg();
   350	      emitVSltiu(iseq, tmp, 1);
   351	
   352	      const llvm::BasicBlock* succ = c.getCaseSuccessor();
   353	      auto moves = collectPhiMoves(*curBB_, *succ);
   354	      std::string label = moves.empty() ? bbLabel(*succ) : makeEdgeLabel();
   355	      if (!moves.empty())
   356	        pendingEdges_.push_back(EdgeBlock{label, bbLabel(*succ), std::move(moves)});
   357	      emitVBranchCond(iseq, label, false);
   358	    }
   359	
   360	    const llvm::BasicBlock* def = si.getDefaultDest();
   361	    auto defMoves = collectPhiMoves(*curBB_, *def);
   362	    std::string defLabel = defMoves.empty() ? bbLabel(*def) : makeEdgeLabel();
   363	    if (!defMoves.empty())
   364	      pendingEdges_.push_back(EdgeBlock{defLabel, bbLabel(*def), std::move(defMoves)});
   365	    emitVBranchUncond(defLabel);
   366	  }
   367	
   368	  // 收集从 pred 进入 succ 时需要执行的 PHI move。
   369	  // 这一步只“记下来”，真正发指令在 emitPhiMoves 里完成。
   370	  llvm::SmallVector<PhiMove, 4> collectPhiMoves(const llvm::BasicBlock& pred,
   371	                                                const llvm::BasicBlock& succ) const
   372	  {
   373	    llvm::SmallVector<PhiMove, 4> moves;
   374	    for (const llvm::Instruction& inst : succ) {
   375	      const auto* phi = llvm::dyn_cast<llvm::PHINode>(&inst);
   376	      if (!phi)
   377	        break;
   378	      const llvm::Value* incoming = phi->getIncomingValueForBlock(&pred);
   379	      if (!incoming)
   380	        llvm::report_fatal_error("missing phi incoming value");
   381	      moves.push_back(PhiMove{vregOf(phi), incoming});
   382	    }
   383	    return moves;
   384	  }
   385	
   386	  // 把一组 PHI move 展开成普通寄存器复制。
   387	  void emitPhiMoves(const llvm::SmallVectorImpl<PhiMove>& moves)
   388	  {
   389	    for (const PhiMove& mv : moves) {
   390	      llvm::Register src = emitLoadValue(mv.src);
   391	      if (src == mv.dst)
   392	        continue;
   393	      emitVMov(mv.dst, src);
   394	    }
   395	  }
   396	
   397	  // 给边块生成一个独立标签，供 branch/switch 插入中转块时使用。
   398	  std::string makeEdgeLabel()
   399	  {
   400	    return ".Ledge." + std::to_string(edgeId_++);
   401	  }
